// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential test for the adaptive scan-once (hash-join-style) branch mode: with thousands of distinct probe keys, a
 * factorized branch must flip from per-key probing to one sequential sweep bucketed by the correlated slot, without
 * changing any result. The store is sized so the switch trigger (1024 distinct keys and probing cost exceeding the
 * branch's estimated size) fires deterministically.
 */
public class LmdbNativeFactorizedScanOnceTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final int HUBS = 3_000;

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			conn.begin();
			for (int hub = 0; hub < HUBS; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				conn.add(subject, p1, vf.createIRI(EX, "a" + hub));
				// two p2 branches per hub, except every 10th hub which has none (inner-join drop)
				if (hub % 10 != 0) {
					conn.add(subject, p2, vf.createIRI(EX, "b" + (hub % 97)));
					conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub + 13) % 97)));
				}
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream().map(Object::toString).sorted().collect(Collectors.toList());
		}
	}

	private void assertSameAsGeneric(String query) {
		List<String> nativeRows = rows(query);
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> genericRows;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			genericRows = rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(nativeRows).as("native vs generic for:\n" + query).isEqualTo(genericRows);
	}

	@Test
	public void scanOnceModeStaysCorrectAndEngages() {
		long buildsBefore = LmdbNativeAggregateCompiler.FactorizedTail.SCAN_ONCE_BUILDS.get();
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(?b) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "}");
		assertThat(LmdbNativeAggregateCompiler.FactorizedTail.SCAN_ONCE_BUILDS.get())
				.as("the branch should have flipped to scan-once mode")
				.isGreaterThan(buildsBefore);
	}

	@Test
	public void scanOnceWithGroupByPrefix() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?a (COUNT(?b) AS ?c) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "} GROUP BY ?a");
	}
}
